import{_ as n,H as o,f as a,i as t}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"内网渗透:横向移动 / 提权 / 域渗透 / C2 流量","description":"","frontmatter":{},"headers":[],"relativePath":"securityLearning/23-内网渗透.md","filePath":"securityLearning/23-内网渗透.md","lastUpdated":1778496697000}'),e={name:"securityLearning/23-内网渗透.md"};function r(i,s,l,p,c,d){return o(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="内网渗透-横向移动-提权-域渗透-c2-流量" tabindex="-1">内网渗透:横向移动 / 提权 / 域渗透 / C2 流量 <a class="header-anchor" href="#内网渗透-横向移动-提权-域渗透-c2-流量" aria-label="Permalink to &quot;内网渗透:横向移动 / 提权 / 域渗透 / C2 流量&quot;">​</a></h1><p>写到这一篇,前两篇刚把&quot;外网怎么打进来&quot;讲完——OSINT 摸清边界、Web 渗透方法论拿下一个 Web Shell——但真正让攻击者拿到价值的<strong>不是这第一台机器</strong>,而是从这台机器出发的<strong>接下来 30 步</strong>。绝大多数新人对&quot;渗透&quot;的想象停在「拿到 shell 就赢了」,真实情况是:<strong>拿到 shell 只是开始,攻击者真正要的是域控、是数据库、是邮箱、是源代码、是 CI/CD 的密钥</strong>——而这些<strong>几乎都不在第一台机器上</strong>。这一篇讲清楚攻击者拿到第一个立足点之后,在内网里<strong>怎么想、怎么走、怎么藏</strong>,但<strong>所有内容只到心智层</strong>——不教任何具体武器化命令,<strong>目的是让 blue team 知道防御要堵哪里</strong>。</p><blockquote><p>一句话先记住:<strong>外网攻击是&quot;撞门&quot;,内网渗透是&quot;在你家里走&quot;</strong>——外网每个动作都很吵(扫描、爆破、注入),内网每个动作都尽量&quot;看起来像合法操作&quot;(用合法凭证、走合法协议、调合法 API)。<strong>这就是为什么内网防御不能靠 WAF 和防火墙</strong>——攻击者已经在边界内,用着合法账号——<strong>只能靠&quot;行为基线&quot;和&quot;最小权限&quot;,看不到这层的企业,等于在内网裸奔</strong>。99% 的&quot;重大数据泄露&quot;,边界都没被打穿,被打穿的是内网。</p></blockquote><hr><h2 id="一、为什么-打进来-只是开始" tabindex="-1">一、为什么&quot;打进来&quot;只是开始 <a class="header-anchor" href="#一、为什么-打进来-只是开始" aria-label="Permalink to &quot;一、为什么&quot;打进来&quot;只是开始&quot;">​</a></h2><p>很多工程师以为&quot;边界守好就万事大吉&quot;——防火墙 / WAF / IDS 围一圈就安全了。这个心智在 2000 年还成立,<strong>现在彻底失效</strong>:边界一定会破(钓鱼邮件 / 1day 没补 / 供应商被打穿,总有一台机器会沦陷);内网信任过度(数据库不要密码、运维网段全互通、SSH 密钥不轮转);横向走一次就赢(拿到一台开发机,从浏览器拿到 GitLab Token / AWS Key,顺着摸到 CI/CD,整个仓库和生产环境一起沦陷)。<strong>Mandiant M-Trends 2024 的数字</strong>:攻击者从「初始访问」到「拿到域控」的中位数是 <strong>不到 24 小时</strong>——应急响应不在一天内启动,基本就是&quot;事后审计&quot;。</p><h3 id="_1-1-内网渗透的本质-把-一台机器-变成-整个域" tabindex="-1">1.1 内网渗透的本质:把&quot;一台机器&quot;变成&quot;整个域&quot; <a class="header-anchor" href="#_1-1-内网渗透的本质-把-一台机器-变成-整个域" aria-label="Permalink to &quot;1.1 内网渗透的本质:把&quot;一台机器&quot;变成&quot;整个域&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一台机器(Web Shell / 钓鱼木马 / 1day)</span></span>
<span class="line"><span>    ↓ 立足 → 侦察 → 提权 → 凭证窃取</span></span>
<span class="line"><span>    ↓ 横向(用偷来的凭证登录第二台)</span></span>
<span class="line"><span>    ↓  ←──── 循环,直到拿到目标</span></span>
<span class="line"><span>最终目标(域控 / 数据库 / 邮箱 / CI/CD)</span></span>
<span class="line"><span>    ↓ 数据外带 → 清理痕迹</span></span></code></pre></div><p><strong>每一步都不是&quot;黑客技术&quot;</strong>——多数情况下,<strong>是用合法工具做合法操作</strong>,只是顺序和目标不合法。<strong>这就是检测的最大难点</strong>:你拦不掉 <code>psexec</code>、<code>wmic</code>、<code>ssh</code>、<code>net use</code>——这些都是运维每天用的工具。</p><h3 id="_1-2-攻击者想的事和你想的不一样" tabindex="-1">1.2 攻击者想的事和你想的不一样 <a class="header-anchor" href="#_1-2-攻击者想的事和你想的不一样" aria-label="Permalink to &quot;1.2 攻击者想的事和你想的不一样&quot;">​</a></h3><table tabindex="0"><thead><tr><th>你以为攻击者想</th><th>攻击者实际想</th></tr></thead><tbody><tr><td>&quot;我要黑掉这家公司&quot;</td><td>&quot;我要拿到域控,然后从域控分发勒索软件&quot;</td></tr><tr><td>&quot;我要找最新的 0day&quot;</td><td>&quot;我要找最旧没补的 1day,因为没人盯&quot;</td></tr><tr><td>&quot;我要写最厉害的 exploit&quot;</td><td>&quot;我要用最朴素的 PowerShell + WMI,不触发 EDR&quot;</td></tr><tr><td>&quot;我要快速拿下&quot;</td><td>&quot;我要潜伏 200 天,确认有备份再发动勒索&quot;</td></tr></tbody></table><p><strong>真正的 APT 不追求&quot;炫技&quot;,追求&quot;不被发现&quot;</strong>——他们用的工具往往简单到惊人,<strong>全是合法管理员工具</strong>。这种打法有个名字:<strong>Living Off the Land(LOTL,就地取材)</strong>。</p><hr><h2 id="二、mitre-att-ck-内网攻击的-通用语言" tabindex="-1">二、MITRE ATT&amp;CK:内网攻击的&quot;通用语言&quot; <a class="header-anchor" href="#二、mitre-att-ck-内网攻击的-通用语言" aria-label="Permalink to &quot;二、MITRE ATT&amp;CK:内网攻击的&quot;通用语言&quot;&quot;">​</a></h2><p>讲内网渗透绕不开 ATT&amp;CK——它把攻击者所有动作分成 <strong>14 个战术阶段</strong>,每个阶段下是具体技术。<strong>蓝队和红队都靠这套框架对齐认知</strong>:红队说&quot;我演练 T1003 LSASS dumping&quot;,蓝队就知道该看哪些日志、哪些 EDR 规则。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1.  Reconnaissance       侦察          (打进来之前,扫外网 / OSINT)</span></span>
<span class="line"><span>2.  Resource Development 准备资源</span></span>
<span class="line"><span>3.  Initial Access       初始访问       ★ 边界破了</span></span>
<span class="line"><span>4.  Execution            执行</span></span>
<span class="line"><span>5.  Persistence          持久化         (重启还在)</span></span>
<span class="line"><span>6.  Privilege Escalation 提权           (普通用户 → root)</span></span>
<span class="line"><span>7.  Defense Evasion      防御绕过</span></span>
<span class="line"><span>8.  Credential Access    凭证窃取       (LSASS / SSH key)</span></span>
<span class="line"><span>9.  Discovery            发现           (内网摸清楚)</span></span>
<span class="line"><span>10. Lateral Movement     横向移动       ★ 走到下一台</span></span>
<span class="line"><span>11. Collection           数据收集</span></span>
<span class="line"><span>12. Command &amp; Control    C2 通信        ★ 远控通道</span></span>
<span class="line"><span>13. Exfiltration         数据外带</span></span>
<span class="line"><span>14. Impact               影响           (勒索 / 破坏 / 篡改)</span></span></code></pre></div><p><strong>3-12 阶段全是&quot;内网渗透&quot;的范围</strong>——ATT&amp;CK 80% 内容都在讲内网怎么走。<strong>它的价值</strong>:把&quot;我们安全吗&quot;这个无法回答的问题,变成&quot;我们对哪些技术有检测覆盖&quot;这个能打分的问题。没 ATT&amp;CK 之前蓝队对话&quot;我们装了杀软挺安全的吧&quot;,有了之后是&quot;T1003 我们覆盖了吗?T1059.001 有规则吗?覆盖率 65%,缺口在持久化和 C2&quot;。这是 Purple Team 的基础(24 篇细讲)。</p><hr><h2 id="三、立足与持久化-重启之后还在" tabindex="-1">三、立足与持久化:重启之后还在 <a class="header-anchor" href="#三、立足与持久化-重启之后还在" aria-label="Permalink to &quot;三、立足与持久化:重启之后还在&quot;">​</a></h2><p>攻击者拿到第一个 shell 后,<strong>第一件做的事不是提权,是持久化</strong>——他们最怕&quot;机器被运维重启 / 进程被杀,辛苦建立的入口没了&quot;。</p><h3 id="_3-1-linux-上-重启还在-的常见姿势" tabindex="-1">3.1 Linux 上&quot;重启还在&quot;的常见姿势 <a class="header-anchor" href="#_3-1-linux-上-重启还在-的常见姿势" aria-label="Permalink to &quot;3.1 Linux 上&quot;重启还在&quot;的常见姿势&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>crontab / systemd timer       定时唤起</span></span>
<span class="line"><span>/etc/rc.local / systemd unit  开机启动</span></span>
<span class="line"><span>~/.bashrc / ~/.profile        用户登录就跑</span></span>
<span class="line"><span>SSH authorized_keys           加自己的公钥</span></span>
<span class="line"><span>PAM 模块替换                  改认证模块,任何密码都能登</span></span>
<span class="line"><span>内核 rootkit                  内核态隐藏进程 / 文件</span></span></code></pre></div><p><strong>防御侧监控</strong>(不是&quot;禁止&quot;,这些命令运维都要用):<code>/etc/cron.*</code> 和 <code>/var/spool/cron/</code> 修改告警;<code>systemctl</code> 新建 service 审计;<code>authorized_keys</code> 变更告警;<code>/etc/pam.d/</code> 任何变更告警(PAM 改了基本就是后门);<code>/lib/modules</code> 下加载未知 ko 告警(rootkit 入口)。</p><h3 id="_3-2-windows-上-重启还在-的常见姿势" tabindex="-1">3.2 Windows 上&quot;重启还在&quot;的常见姿势 <a class="header-anchor" href="#_3-2-windows-上-重启还在-的常见姿势" aria-label="Permalink to &quot;3.2 Windows 上&quot;重启还在&quot;的常见姿势&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Run / RunOnce 注册表项        登录自动跑</span></span>
<span class="line"><span>计划任务(schtasks)</span></span>
<span class="line"><span>服务(services.msc 加项)</span></span>
<span class="line"><span>WMI 事件订阅                  事件触发就跑,隐蔽性极强</span></span>
<span class="line"><span>DLL 劫持                      放假 DLL 在系统目录</span></span>
<span class="line"><span>Image File Execution Options  劫持任意 .exe 的启动</span></span>
<span class="line"><span>Logon Script</span></span>
<span class="line"><span>UEFI / Bootkit                硬件级,重装系统都干不掉</span></span></code></pre></div><p><strong>WMI 事件订阅特别要关注</strong>——它不在普通&quot;启动项&quot;清单里,很多运维根本不知道有这东西,<strong>APT 最爱</strong>(Stuxnet 就用了)。</p><p><strong>对蓝队的好消息</strong>:<strong>持久化必然在磁盘 / 注册表 / 配置文件留痕</strong>——没有持久化,攻击者重启就完蛋;有了持久化,<strong>就有可被扫到的 IoC(Indicator of Compromise)</strong>。EDR / Sysmon / auditd 主要靠这个找入侵——<strong>攻击者最薄弱的环节,也是蓝队最强的环节</strong>。</p><hr><h2 id="四、信息收集-在内网里-找路" tabindex="-1">四、信息收集:在内网里&quot;找路&quot; <a class="header-anchor" href="#四、信息收集-在内网里-找路" aria-label="Permalink to &quot;四、信息收集:在内网里&quot;找路&quot;&quot;">​</a></h2><p>打外网时信息收集靠 Google + scan,<strong>打内网时信息收集靠&quot;在机器内部翻东西&quot;</strong>。</p><h3 id="_4-1-攻击者在第一台机器上-翻-什么" tabindex="-1">4.1 攻击者在第一台机器上&quot;翻&quot;什么 <a class="header-anchor" href="#_4-1-攻击者在第一台机器上-翻-什么" aria-label="Permalink to &quot;4.1 攻击者在第一台机器上&quot;翻&quot;什么&quot;">​</a></h3><p><strong>网络拓扑</strong>:</p><ul><li>看 <code>/etc/hosts</code>、<code>route</code>、<code>ip route</code>、ARP 表</li><li>看历史 SSH 连接(<code>~/.bash_history</code>、<code>~/.ssh/known_hosts</code>)</li><li>内网 DNS 反向查询整段</li><li>抓本机网络流量看有谁在和这台机器说话</li></ul><p><strong>凭证</strong>:</p><ul><li>浏览器保存的密码 / cookie / 自动填充</li><li>SSH 私钥(<code>~/.ssh/id_*</code>)和它能登的所有机器</li><li><code>~/.aws/credentials</code>、<code>~/.docker/config.json</code>、<code>~/.kube/config</code></li><li>Git 仓库里 hard-code 的 token(<code>.env</code> 文件、配置文件)</li><li>进程命令行参数(<code>ps auxf</code> 经常能看到密码作为参数)</li><li>历史命令行(<code>.bash_history</code> 有人 <code>mysql -u root -pxxx</code>)</li></ul><p><strong>服务发现</strong>:</p><ul><li>内网端口扫描(慢、隐蔽地扫,<strong>不会用 nmap 那种吼一嗓子</strong>)</li><li>LDAP 查询(域内能拿到所有用户和机器列表)</li><li>mDNS / NetBIOS 广播</li><li>看本机 <code>netstat</code> 知道这台机器连了哪些&quot;重要服务&quot;</li></ul><h3 id="_4-2-防御侧要监控什么" tabindex="-1">4.2 防御侧要监控什么 <a class="header-anchor" href="#_4-2-防御侧要监控什么" aria-label="Permalink to &quot;4.2 防御侧要监控什么&quot;">​</a></h3><p><strong>异常的 LDAP 查询</strong>——一台普通办公电脑,<strong>不应该有&quot;列出所有域用户&quot;这种请求</strong>。攻击者一上来就喜欢 dump 整个域(用 BloodHound 这类工具),触发的 LDAP 查询模式跟人类操作完全不同。</p><p><strong>异常的端口扫描</strong>——内部机器之间有&quot;正常通信模式&quot;,突然一台机器连大量内网 IP 的同一个端口(445 / 22 / 3389)→ 大概率横向探测。</p><p><strong>密钥文件被异常读取</strong>——可以用 auditd / Sysmon 监控 <code>~/.ssh/</code>、<code>%APPDATA%\\Mozilla\\Firefox\\Profiles\\*\\logins.json</code> 这类文件的读取,<strong>正常用户不会&quot;突然 cat 浏览器密码库&quot;</strong>。</p><hr><h2 id="五、提权的心智-不讲具体方法" tabindex="-1">五、提权的心智(不讲具体方法) <a class="header-anchor" href="#五、提权的心智-不讲具体方法" aria-label="Permalink to &quot;五、提权的心智(不讲具体方法)&quot;">​</a></h2><p>拿到第一个 shell 通常是低权限的(www-data / IIS 之类)。<strong>攻击者要从普通用户 → root / SYSTEM,才有真正大规模操作的能力</strong>。</p><h3 id="_5-1-linux-提权的几个心智方向" tabindex="-1">5.1 Linux 提权的几个心智方向 <a class="header-anchor" href="#_5-1-linux-提权的几个心智方向" aria-label="Permalink to &quot;5.1 Linux 提权的几个心智方向&quot;">​</a></h3><ul><li><strong>SUID 错配</strong>:某二进制设了 SUID(以 root 跑),但内部允许执行命令或读任意文件。<strong>任何 SUID 二进制都是攻击面</strong>,要审计每一个;定期扫 <code>find / -perm -4000</code> 与白名单比对</li><li><strong>sudo 错配</strong>:<code>sudoers</code> 给了&quot;无密码 sudo 某命令&quot;,但这个命令能逃逸(<code>sudo vi</code> 进去 <code>:!sh</code> 就是 root)。<strong>给 sudo 要给到具体不可逃逸的命令</strong>,不要给 vim / less / find / awk / 任何脚本解释器。GTFOBins 这个网站列举了哪些命令能逃出来——<strong>蓝队也要看,知道自己 sudoers 给了什么风险</strong></li><li><strong>内核漏洞</strong>:Dirty Pipe / Dirty COW / OverlayFS 可直接从普通用户提到 root。<strong>未及时打补丁的内核就是开放门</strong>,<code>uname -r</code> 对比 CVE 数据库,过期了告警</li><li><strong>capabilities 错配</strong>:Linux 把 root 拆成 38 个 capability,<code>CAP_SYS_ADMIN</code> 之类高权就是半个 root。<code>getcap -r / 2&gt;/dev/null</code> 看有哪些可疑 capability</li></ul><h3 id="_5-2-windows-提权的几个心智方向" tabindex="-1">5.2 Windows 提权的几个心智方向 <a class="header-anchor" href="#_5-2-windows-提权的几个心智方向" aria-label="Permalink to &quot;5.2 Windows 提权的几个心智方向&quot;">​</a></h3><ul><li><strong>UAC bypass</strong>:UAC 让管理员账户大多数时候以普通权限运行,需要提权弹窗。<strong>Bypass 不算严格意义&quot;提权&quot;</strong>(本身已是管理员),但 EDR 视为提权。靠 COM 接口 / 自动提升白名单 / 注册表劫持绕弹窗。<strong>防御</strong>:UAC 等级调到最高</li><li><strong>SeImpersonate 滥用</strong>:Windows 服务账户(IIS / SQL Server)默认带 <code>SeImpersonatePrivilege</code>,可&quot;伪装&quot;成请求来的客户端身份——配合&quot;骗一个高权限服务连进来&quot;(Potato 系列),就能拿 SYSTEM。<strong>防御</strong>:服务尽量用 Managed Service Account</li><li><strong>令牌窃取</strong>:拿到 SYSTEM 后&quot;偷&quot;其他登录用户的 token,<strong>伪装成域管理员</strong>,这是横向到域控的常见跳板</li></ul><h3 id="_5-3-防御侧-提权的-信号" tabindex="-1">5.3 防御侧:提权的&quot;信号&quot; <a class="header-anchor" href="#_5-3-防御侧-提权的-信号" aria-label="Permalink to &quot;5.3 防御侧:提权的&quot;信号&quot;&quot;">​</a></h3><p><strong>多数提权都会产生异常进程链</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正常:explorer.exe → cmd.exe(用户主动开)</span></span>
<span class="line"><span>异常:w3wp.exe(IIS) → cmd.exe → whoami           ← 严重告警</span></span>
<span class="line"><span>异常:sqlservr.exe → powershell.exe -enc &lt;base64&gt; ← 严重告警</span></span>
<span class="line"><span>异常:Office 应用 → cmd.exe / powershell.exe       ← 钓鱼宏的典型</span></span></code></pre></div><p><strong>Sysmon Event ID 1(进程创建)</strong> + <strong>父子进程关系</strong> 是检测提权和横向的金矿——任何&quot;不该派生 shell 的服务派生了 shell&quot;,都值得告警。<strong>EDR 的基础规则就是这套</strong>。</p><hr><h2 id="六、凭证窃取-内网渗透的核心货币" tabindex="-1">六、凭证窃取:内网渗透的核心货币 <a class="header-anchor" href="#六、凭证窃取-内网渗透的核心货币" aria-label="Permalink to &quot;六、凭证窃取:内网渗透的核心货币&quot;">​</a></h2><p>横向移动 99% 靠<strong>偷来的凭证</strong>而不是&quot;再打一遍漏洞&quot;——因为<strong>凭证用起来像合法操作</strong>,扫描和爆破像攻击。</p><p>凭证有三种存在形式:<strong>明文密码</strong>(用户输入 / 配置文件 hard-code / 浏览器明文保存)、<strong>哈希</strong>(Windows NTLM 哈希、Linux <code>/etc/shadow</code>)、<strong>票据 / 令牌</strong>(Kerberos 票据、OAuth Token、Session Cookie、JWT)。<strong>心智</strong>:凭证不一定要&quot;破解&quot;,只要&quot;能用&quot;就行——这是 Pass-the-Hash / Pass-the-Ticket 的核心思想。</p><h3 id="_6-1-windows-凭证窃取-只讲心智" tabindex="-1">6.1 Windows 凭证窃取(只讲心智) <a class="header-anchor" href="#_6-1-windows-凭证窃取-只讲心智" aria-label="Permalink to &quot;6.1 Windows 凭证窃取(只讲心智)&quot;">​</a></h3><p><strong>LSASS(Local Security Authority Subsystem Service)</strong> 是 Windows 管认证的进程,<strong>内存里缓存了所有当前登录用户的凭证</strong>(NTLM 哈希、Kerberos 票据,有时甚至有明文)。攻击者拿到本地管理员,<strong>dump LSASS 内存</strong>就能拿到登录过这台机器的所有用户凭证——<strong>包括域管理员路过留下的</strong>。</p><blockquote><p>Mimikatz(2014 年开源)是干这事最出名的工具,也是 Windows 内网渗透的&quot;教父级&quot;工具。<strong>它本身是合法的安全研究工具,但被滥用得太厉害,所有 EDR 都在重点盯</strong>。</p></blockquote><p><strong>防御</strong>:</p><ul><li>开启 <strong>Credential Guard</strong>(Windows 10+):用 VBS 虚拟化隔离 LSASS 凭证,从内核态都摸不到</li><li>LSASS <strong>保护模式</strong>(RunAsPPL):限制能 attach 它的进程</li><li><strong>限制域管理员登录范围</strong>:<strong>绝对不要让域管登录普通办公电脑或 Web 服务器</strong>——一旦那机器沦陷,LSASS 里的域管哈希就被拿到了。这是&quot;分层管理(Tiered Admin Model)&quot;的核心</li><li>EDR 监控对 LSASS 的&quot;读内存&quot;操作(<code>OpenProcess</code> with <code>PROCESS_VM_READ</code>)→ 几乎都是异常</li></ul><h3 id="_6-2-linux-浏览器凭证" tabindex="-1">6.2 Linux &amp; 浏览器凭证 <a class="header-anchor" href="#_6-2-linux-浏览器凭证" aria-label="Permalink to &quot;6.2 Linux &amp; 浏览器凭证&quot;">​</a></h3><p>Linux 侧:<code>/etc/shadow</code>(哈希,拿到能离线爆破)、<code>~/.ssh/id_*</code>(私钥,大多没设密码,等于通行证)、<code>~/.aws/credentials</code> / <code>~/.kube/config</code> / <code>~/.docker/config.json</code>、内存里的 <code>ssh-agent</code> 密钥、环境变量里的 token(<code>printenv</code> 一眼)。</p><p>浏览器是凭证富矿——保存的密码 / cookie / 自动填充 / OAuth Token 全在用户家目录,用本机 DPAPI 密钥加密,<strong>拿到这个用户的权限就能解密</strong>。<strong>防御</strong>:公司机器禁用浏览器保存密码,统一 SSO + MFA;关键账户每次走 MFA;EDR 监控对 <code>Login Data</code> / <code>Cookies</code> 的异常读取。</p><hr><h2 id="七、横向移动-从一台到下一台" tabindex="-1">七、横向移动:从一台到下一台 <a class="header-anchor" href="#七、横向移动-从一台到下一台" aria-label="Permalink to &quot;七、横向移动:从一台到下一台&quot;">​</a></h2><p>拿到凭证之后,<strong>怎么用这凭证登第二台</strong>?这就是横向移动。</p><h3 id="_7-1-三个核心心智-不一定要密码" tabindex="-1">7.1 三个核心心智:不一定要密码 <a class="header-anchor" href="#_7-1-三个核心心智-不一定要密码" aria-label="Permalink to &quot;7.1 三个核心心智:不一定要密码&quot;">​</a></h3><p><strong>Pass-the-Hash(PtH)</strong>:Windows NTLM 协议有个设计缺陷——<strong>认证时只比对哈希,不需要原始密码</strong>。如果你拿到了某用户的 NTLM 哈希,就可以&quot;伪装&quot;成他登录任何接受 NTLM 的服务(SMB / WMI / WinRM),<strong>完全不需要破解出明文密码</strong>。</p><ul><li>出现的根本原因:NTLM 是 90 年代的设计,<strong>哈希就是凭证本身</strong></li><li>解决:<strong>禁用 NTLM,全用 Kerberos</strong>;但很多老系统迁不动</li></ul><p><strong>Pass-the-Ticket(PtT)</strong>:Kerberos 协议也有类似问题——拿到一个有效的 TGT(Ticket Granting Ticket)或 ST(Service Ticket),<strong>可以直接注入到当前会话,免认证访问目标服务</strong>。</p><ul><li>不同于 PtH,<strong>Kerberos 票据有时效</strong>(默认 10 小时),但已经够横向了</li><li>防御:监控异常票据使用(同一个 TGT 突然从不同 IP 出现)</li></ul><p><strong>SSH 密钥滥用</strong>:开发机和服务器之间 SSH 互通,运维一台拿一把私钥,<strong>这把私钥能登 100 台机器</strong>。一旦运维机器沦陷,<strong>整个 fleet 全沦陷</strong>。</p><ul><li>防御:<strong>SSH 密钥不要&quot;一把通天下&quot;</strong>,按角色 / 环境分密钥;用 SSH CA 签证书,<strong>证书带过期时间</strong></li><li>进阶:把 SSH 入口都收到一个 bastion(跳板机)上,<strong>生产机不直接接受密钥认证</strong>,只接受跳板转发的会话</li></ul><h3 id="_7-2-横向用的协议与端口" tabindex="-1">7.2 横向用的协议与端口 <a class="header-anchor" href="#_7-2-横向用的协议与端口" aria-label="Permalink to &quot;7.2 横向用的协议与端口&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SMB         445       Windows 文件共享 + 远程执行(PsExec / WMI)</span></span>
<span class="line"><span>WinRM       5985/5986 Windows 远程管理(PowerShell Remoting)</span></span>
<span class="line"><span>RDP         3389      远程桌面</span></span>
<span class="line"><span>WMI         135 + 动态  Windows 管理规范(隐蔽性强)</span></span>
<span class="line"><span>SSH         22        Linux 远程登录</span></span>
<span class="line"><span>RPC         135 + 动态  各种远程调用</span></span>
<span class="line"><span>LDAP        389/636   域信息查询</span></span></code></pre></div><p><strong>防御侧最关键的两件事</strong>:</p><ol><li><strong>网络分段</strong>:办公网、开发网、生产网、域控网严格分开。<strong>默认禁止跨段通信</strong>,只开必需端口。<strong>没有分段的内网,一台沦陷 = 全沦陷</strong></li><li><strong>横向协议监控</strong>:SMB / WMI / WinRM 的&quot;非常规来源&quot;是横向的最强信号——一台财务 PC 不该向另一台财务 PC 发 PsExec</li></ol><hr><h2 id="八、active-directory-域渗透心智-只讲概念" tabindex="-1">八、Active Directory 域渗透心智(只讲概念) <a class="header-anchor" href="#八、active-directory-域渗透心智-只讲概念" aria-label="Permalink to &quot;八、Active Directory 域渗透心智(只讲概念)&quot;">​</a></h2><p>90% 的中大型企业用 AD(Active Directory)管 Windows 域——<strong>搞定 AD = 搞定整个公司</strong>。AD 攻击是内网渗透的&quot;皇冠&quot;,<strong>也是这一篇最危险的部分,所以只讲概念</strong>。</p><h3 id="_8-1-ad-的核心信任模型" tabindex="-1">8.1 AD 的核心信任模型 <a class="header-anchor" href="#_8-1-ad-的核心信任模型" aria-label="Permalink to &quot;8.1 AD 的核心信任模型&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>域控(DC)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── 用户账户和密码哈希都存在这里(NTDS.dit 数据库)</span></span>
<span class="line"><span>  ├── Kerberos KDC 在这里(发票据)</span></span>
<span class="line"><span>  └── LDAP 树(组织结构、ACL)在这里</span></span>
<span class="line"><span>   ↓ 信任</span></span>
<span class="line"><span>所有域成员机器(笔记本 / 服务器)</span></span></code></pre></div><p><strong>核心心智</strong>:<strong>DC 是单点信任根</strong>——拿到 DC,等于拿到所有用户的所有哈希、所有票据签发权限。<strong>DC 沦陷 = 域沦陷 = 公司沦陷</strong>。</p><h3 id="_8-2-kerberoasting" tabindex="-1">8.2 Kerberoasting <a class="header-anchor" href="#_8-2-kerberoasting" aria-label="Permalink to &quot;8.2 Kerberoasting&quot;">​</a></h3><p><strong>心智</strong>:Kerberos 中,任何域用户都可以申请&quot;某个服务&quot;的票据(ST),这个票据是用<strong>服务账户的密码哈希</strong>加密的。<strong>攻击者申请一堆票据,离线爆破弱密码的服务账户</strong>——服务账户密码通常是 SQL Server / Exchange 之类的,<strong>长期不改,而且是管理员密码</strong>。</p><p><strong>防御</strong>:</p><ul><li>服务账户密码要<strong>长(25 字符+)而且随机</strong>,这样离线爆破不出来</li><li>用 <strong>Managed Service Account(gMSA)</strong>,密码 AD 自动管,<strong>人都拿不到</strong></li><li>监控异常的&quot;批量 TGS 请求&quot;</li></ul><h3 id="_8-3-golden-ticket" tabindex="-1">8.3 Golden Ticket <a class="header-anchor" href="#_8-3-golden-ticket" aria-label="Permalink to &quot;8.3 Golden Ticket&quot;">​</a></h3><p><strong>心智</strong>:Kerberos 中所有 TGT 都用 <strong><code>krbtgt</code> 账户的哈希签发</strong>。如果攻击者拿到 <code>krbtgt</code> 的哈希(意味着已经搞定了 DC),<strong>就可以伪造任意用户的 TGT</strong>——包括根本不存在的用户、伪造的超级管理员。这个伪造的票据叫 Golden Ticket,<strong>只要 <code>krbtgt</code> 哈希不变,就能用 10 年</strong>。</p><p><strong>防御</strong>:</p><ul><li><strong>定期(2 次)重置 <code>krbtgt</code> 账户密码</strong>——这是 AD 运维的硬性安全要求</li><li>监控异常的 TGT(签发时间和实际时间不一致、字段异常)</li><li>一旦怀疑 DC 沦陷,<strong>必须重置 <code>krbtgt</code> 两次</strong>(Kerberos 设计上保留前一个密码可用)</li></ul><h3 id="_8-4-dcsync" tabindex="-1">8.4 DCSync <a class="header-anchor" href="#_8-4-dcsync" aria-label="Permalink to &quot;8.4 DCSync&quot;">​</a></h3><p><strong>心智</strong>:AD 多 DC 之间用一个叫 <strong>DRSUAPI</strong> 的协议同步数据,<strong>这个协议允许&quot;请求复制账户哈希&quot;</strong>。任何拥有&quot;复制目录变更&quot;权限的账户(默认是 Domain Admins 和 DC 本身)都能调这个 API,<strong>远程&quot;问 DC 要任意账户的哈希&quot;——包括 <code>krbtgt</code></strong>。</p><p>也就是说:<strong>攻击者不需要真的登上 DC,只要有合适的权限,就能从远程把整个域的哈希&quot;同步&quot;出来</strong>——这就是从域管 → Golden Ticket 的常用跳板。</p><p><strong>防御</strong>:</p><ul><li>严格控制&quot;复制目录变更&quot;权限——只有 DC 应该有,<strong>任何用户/服务账户拿到这个权限都是异常</strong></li><li>监控 DRSUAPI 调用,<strong>任何来自非 DC 的复制请求都告警</strong></li></ul><h3 id="_8-5-bloodhound-攻防都在用的工具" tabindex="-1">8.5 BloodHound:攻防都在用的工具 <a class="header-anchor" href="#_8-5-bloodhound-攻防都在用的工具" aria-label="Permalink to &quot;8.5 BloodHound:攻防都在用的工具&quot;">​</a></h3><p><strong>心智</strong>:AD 里的 ACL 关系极其复杂(谁能登谁、谁能改谁、谁继承了什么),<strong>人工看根本看不出&quot;从 A 到域管&quot;的路径</strong>。BloodHound 用图数据库把 AD 关系画出来,<strong>红队用来找最短攻击路径,蓝队用来审计自己的 ACL 错配</strong>。</p><blockquote><p>这是少数&quot;攻防对称&quot;的工具——<strong>蓝队不用 BloodHound,你根本不知道自己 AD 多脆弱</strong>。</p></blockquote><hr><h2 id="九、c2-流量-命令通道的猫鼠游戏" tabindex="-1">九、C2 流量:命令通道的猫鼠游戏 <a class="header-anchor" href="#九、c2-流量-命令通道的猫鼠游戏" aria-label="Permalink to &quot;九、C2 流量:命令通道的猫鼠游戏&quot;">​</a></h2><p>攻击者在内网里跑,<strong>总要有个&quot;远程控制通道&quot;</strong>——把自己的指令送进来,把窃取的数据送出去。这就是 <strong>C2(Command &amp; Control)</strong>。C2 是所有 EDR / IDS / 流量分析的重点战场。</p><h3 id="_9-1-c2-的演化-藏在合法流量里" tabindex="-1">9.1 C2 的演化:藏在合法流量里 <a class="header-anchor" href="#_9-1-c2-的演化-藏在合法流量里" aria-label="Permalink to &quot;9.1 C2 的演化:藏在合法流量里&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2000 年代:    自定义协议、固定端口      → 一抓一个准</span></span>
<span class="line"><span>2010 年代:    HTTP/HTTPS 伪装合法 Web    → 流量加密了,但能从行为分析</span></span>
<span class="line"><span>2015+ :       域前置(Domain Fronting)  → 借合法 CDN 隐藏真实 C2</span></span>
<span class="line"><span>2018+ :       DNS / DoH(DNS over HTTPS)→ 用 DNS 当通道,出口墙也拦不掉</span></span>
<span class="line"><span>2020+ :       合法 SaaS 当 C2            → 借 GitHub / Slack / Dropbox / Telegram</span></span></code></pre></div><p><strong>心智</strong>:<strong>好的 C2 流量,看起来要像 100% 合法的业务流量</strong>——和 Google / Cloudflare / 公司 OA 一模一样。这是为什么传统签名/特征检测对现代 C2 几乎无效。</p><h3 id="_9-2-域前置-domain-fronting" tabindex="-1">9.2 域前置(Domain Fronting) <a class="header-anchor" href="#_9-2-域前置-domain-fronting" aria-label="Permalink to &quot;9.2 域前置(Domain Fronting)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>攻击者的真实 C2:    evil-c2.attacker.com  (托管在某 CDN 上)</span></span>
<span class="line"><span>看起来访问的:       www.microsoft.com     (TLS SNI / 流量目的)</span></span>
<span class="line"><span>实际 HTTP Host 头:  evil-c2.attacker.com  (CDN 根据 Host 转发)</span></span></code></pre></div><p><strong>为什么有效</strong>:防火墙看到的是&quot;访问 Microsoft 的 IP&quot;,根本拦不掉(总不能拦 Microsoft)。<strong>HTTP Host 头在 TLS 加密内层,IDS 看不到</strong>。</p><p><strong>防御</strong>:</p><ul><li>主流 CDN(Google / AWS / Azure)2018 年后陆续<strong>禁用了 Domain Fronting</strong>,但仍有小厂可滥用</li><li>出口流量做 <strong>TLS 中间人解密 + Host 头审计</strong>(合规问题大,要慎用)</li><li><strong>零信任出口策略</strong>:只允许业务需要的域名访问,其他全拦——比 Domain Fronting 检测更彻底</li></ul><h3 id="_9-3-dns-doh-c2" tabindex="-1">9.3 DNS / DoH C2 <a class="header-anchor" href="#_9-3-dns-doh-c2" aria-label="Permalink to &quot;9.3 DNS / DoH C2&quot;">​</a></h3><p><strong>心智</strong>:DNS 是几乎不会被拦的协议(没了 DNS 业务全废)。攻击者把指令编码到 DNS 查询里,<strong>外发数据编码到子域名里</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查询: aGVsbG8gd29ybGQ.attacker.com    (子域名是 base64 数据)</span></span>
<span class="line"><span>回包: TXT 记录里塞返回数据</span></span></code></pre></div><p><strong>DoH(DNS over HTTPS)</strong> 让这事更难——DNS 查询走 HTTPS 到 8.8.8.8 / 1.1.1.1,<strong>企业 DNS 服务器都看不到</strong>。</p><p><strong>防御</strong>:</p><ul><li>强制走企业 DNS,<strong>禁止终端直连 8.8.8.8 / 1.1.1.1</strong></li><li>DNS 流量分析:<strong>正常 DNS 查询的子域名长度、字符分布、查询频率有基线</strong>,大量长子域名或高熵字符串 → 大概率隧道</li><li>阻断已知 DoH 服务器 IP</li></ul><h3 id="_9-4-行为基线-c2-检测的终极武器" tabindex="-1">9.4 行为基线:C2 检测的终极武器 <a class="header-anchor" href="#_9-4-行为基线-c2-检测的终极武器" aria-label="Permalink to &quot;9.4 行为基线:C2 检测的终极武器&quot;">​</a></h3><p>无论 C2 怎么伪装,<strong>它都有&quot;行为指纹&quot;</strong>:</p><ul><li><strong>心跳间隔</strong>:大多 C2 是固定间隔回连(beaconing),<strong>正常浏览器不会&quot;每 60 秒访问同一个 URL&quot;</strong></li><li><strong>Jitter(抖动)</strong>:好的 C2 会加随机抖动模拟人,但抖动也有分布特征</li><li><strong>流量比例</strong>:正常 HTTP 是&quot;请求小、回包大&quot;(下载内容),C2 通常&quot;请求大、回包小&quot;(命令短、数据回传)</li><li><strong>JA3 / JA3S TLS 指纹</strong>:不同 TLS 库的握手特征不同,<strong>Cobalt Strike 默认配置的 JA3 是已知的</strong></li><li><strong>User-Agent / 时间分布</strong>:夜里 3 点公司没人但有流量,基本不是好事</li></ul><p><strong>这就是为什么&quot;NDR(Network Detection and Response)&quot;成为新一代防御核心</strong>——它不看流量内容,看流量模式。</p><hr><h2 id="十、cobalt-strike-mimikatz-绕不开的-行业术语" tabindex="-1">十、Cobalt Strike / Mimikatz:绕不开的&quot;行业术语&quot; <a class="header-anchor" href="#十、cobalt-strike-mimikatz-绕不开的-行业术语" aria-label="Permalink to &quot;十、Cobalt Strike / Mimikatz:绕不开的&quot;行业术语&quot;&quot;">​</a></h2><p>任何讲内网渗透绕不开这两个名字。<strong>这里只讲它们&quot;为什么重要&quot;,不讲怎么用</strong>。</p><p><strong>Cobalt Strike(CS)</strong>:2012 年发布的商业渗透测试平台。提供&quot;团队服务器 + Beacon(植入端)&quot;的完整 C2 框架——支持 HTTP / HTTPS / DNS / SMB 通道、内置后渗透模块、有 GUI、能多人协作。<strong>90% 真实勒索软件事件都能看到 CS 的影子</strong>——因为它被破解(&quot;裸奔版&quot;)在地下流通,门槛极低;Beacon 通信默认很&quot;像样&quot;,防御方需要训练才能识别。<strong>蓝队要懂的</strong>:CS Beacon 旧版默认配置有明显特征(JA3 指纹、特定 Cookie 名),<code>jump</code> / <code>runas</code> / <code>mimikatz</code> 模块的进程链有典型特征;<strong>不要试图&quot;封 IP&quot;</strong>——team server IP 在变,要靠行为检测。</p><p><strong>Mimikatz</strong>:法国研究员 gentilkiwi 2007 年开发,原本用来&quot;展示 Windows 凭证存储设计缺陷&quot;——成了横扫世界的攻击神器。能 dump LSASS、操作 LSA 注入凭证、DCSync、Pass-the-Hash / Pass-the-Ticket / Golden Ticket / Silver Ticket。<strong>它是 EDR 的&quot;试金石&quot;</strong>——任何 EDR 必须能检测原版 Mimikatz。但攻击者会用 <strong>C# 重写 / .NET 反射加载 / fileless 内存执行</strong>,简单签名拦不住。<strong>本质防御</strong>:Credential Guard + LSASS 保护 + 分层管理(域管不下沉)。</p><hr><h2 id="十一、数据外带-最后一公里也要藏" tabindex="-1">十一、数据外带:最后一公里也要藏 <a class="header-anchor" href="#十一、数据外带-最后一公里也要藏" aria-label="Permalink to &quot;十一、数据外带:最后一公里也要藏&quot;">​</a></h2><p>数据偷出来之前不算成功——但外带恰恰是<strong>最容易被流量分析抓到的环节</strong>。10 GB 的数据库 dump 发出去,无论怎么藏都难看不出异常。</p><h3 id="_11-1-常见外带通道" tabindex="-1">11.1 常见外带通道 <a class="header-anchor" href="#_11-1-常见外带通道" aria-label="Permalink to &quot;11.1 常见外带通道&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 直接 HTTPS 上传到 attacker.com         (最朴素,但容易被 DLP 拦)</span></span>
<span class="line"><span>2. 借合法云盘(Dropbox / OneDrive)        (流量看着合法)</span></span>
<span class="line"><span>3. DNS 隧道                                (慢,但能穿越严防火墙)</span></span>
<span class="line"><span>4. ICMP 隧道                              (老套但有人用)</span></span>
<span class="line"><span>5. 分段慢漏(每天偷一点,慢到看不出)</span></span>
<span class="line"><span>6. 借合法服务(Telegram / Discord / Gist) (新趋势)</span></span></code></pre></div><h3 id="_11-2-防御-dlp-流量基线" tabindex="-1">11.2 防御:DLP + 流量基线 <a class="header-anchor" href="#_11-2-防御-dlp-流量基线" aria-label="Permalink to &quot;11.2 防御:DLP + 流量基线&quot;">​</a></h3><ul><li><strong>数据分级</strong>:核心数据库 / 源码 / 客户数据加水印 / Canary Token,<strong>一旦泄露能溯源</strong></li><li><strong>DLP(Data Loss Prevention)</strong>:出口流量做内容审计,识别&quot;信用卡号 / 身份证号 / 关键字段&quot;</li><li><strong>流量异常基线</strong>:一台办公电脑日常上传 &lt; 100MB,突然上传 5GB → 告警</li><li><strong>出口白名单</strong>:只允许必要的域名/服务,<strong>默认禁止所有未审批的云存储</strong></li></ul><hr><h2 id="十二、防御视角-blue-team-怎么堵" tabindex="-1">十二、防御视角:Blue Team 怎么堵 <a class="header-anchor" href="#十二、防御视角-blue-team-怎么堵" aria-label="Permalink to &quot;十二、防御视角:Blue Team 怎么堵&quot;">​</a></h2><p>讲了这么多攻击心智,<strong>这一节才是这一篇最值钱的部分</strong>。</p><h3 id="_12-1-三层纵深" tabindex="-1">12.1 三层纵深 <a class="header-anchor" href="#_12-1-三层纵深" aria-label="Permalink to &quot;12.1 三层纵深&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 不让攻击者进来(Initial Access)</span></span>
<span class="line"><span>   - 钓鱼防护 / 邮件网关</span></span>
<span class="line"><span>   - 边界 WAF / 漏洞扫描 / 补丁</span></span>
<span class="line"><span>   - MFA(MFA 能挡 99% 的凭证爆破和钓鱼)</span></span>
<span class="line"><span>   - 终端杀软 / EDR</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 进来了让攻击者动不了(Lateral)</span></span>
<span class="line"><span>   - 网络分段</span></span>
<span class="line"><span>   - 最小权限(尤其域管不下沉)</span></span>
<span class="line"><span>   - 服务账户用 gMSA</span></span>
<span class="line"><span>   - EDR + Sysmon + 日志集中</span></span>
<span class="line"><span>   - 蜜罐(Canary Token / Honey Account)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 动了能马上发现 + 干掉(Detection &amp; Response)</span></span>
<span class="line"><span>   - SOC / SIEM / 7x24 监控</span></span>
<span class="line"><span>   - ATT&amp;CK 覆盖率打分</span></span>
<span class="line"><span>   - 应急响应预案 + 桌面演练</span></span>
<span class="line"><span>   - 备份隔离(防勒索)</span></span></code></pre></div><p><strong>心智</strong>:<strong>单层防御一定会破</strong>——别指望&quot;边界 + 杀软&quot;挡一切。<strong>纵深 + 快速发现 + 快速响应</strong> 才是现代防御的核心。</p><h3 id="_12-2-edr-vs-杀软的区别" tabindex="-1">12.2 EDR vs 杀软的区别 <a class="header-anchor" href="#_12-2-edr-vs-杀软的区别" aria-label="Permalink to &quot;12.2 EDR vs 杀软的区别&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统杀软:    比文件签名,病毒库扫文件</span></span>
<span class="line"><span>EDR:        看进程行为,记录所有事件,可回查 + 主动追溯</span></span></code></pre></div><p><strong>杀软只能挡&quot;已知坏文件&quot;</strong>——LOTL(就地取材)的攻击者根本不下载文件,只用合法工具。<strong>EDR 看的是&quot;行为模式异常&quot;</strong>——<code>Word → cmd → powershell → encoded command</code> 这种链路,无论用什么文件都告警。</p><h3 id="_12-3-蜜罐-最小权限的硬纪律" tabindex="-1">12.3 蜜罐 &amp; 最小权限的硬纪律 <a class="header-anchor" href="#_12-3-蜜罐-最小权限的硬纪律" aria-label="Permalink to &quot;12.3 蜜罐 &amp; 最小权限的硬纪律&quot;">​</a></h3><p><strong>蜜罐:让攻击者主动暴露</strong>——在 AD 里建一个&quot;看起来很重要&quot;的账户(<code>backup_admin</code> 这种名字),没人会用它,但攻击者扫到一定会试登录 → 一登录就告警。Canary Token 在敏感目录放假文件(<code>passwords.docx</code>、<code>aws-keys.txt</code>),被打开/读取就触发回调。内网可放假的 SQL / SSH 服务,有人扫一连就报警。<strong>蜜罐的价值</strong>:<strong>误报率极低</strong>——正常业务不会碰这些,一旦触发 99% 是真攻击。</p><p><strong>最小权限</strong>:域管账户只能从特定&quot;管理工作站(PAW)&quot;登录,<strong>绝不上普通办公电脑</strong>;服务账户拆细,一个服务一个账户;SSH 密钥按角色拆,跳板机统一管理;数据库账户分读 / 写 / 管理,<strong>应用绝不用 root 连库</strong>;CI/CD 凭证轮转,默认最短有效期。</p><hr><h2 id="十三、内网安全加固-checklist" tabindex="-1">十三、内网安全加固 checklist <a class="header-anchor" href="#十三、内网安全加固-checklist" aria-label="Permalink to &quot;十三、内网安全加固 checklist&quot;">​</a></h2><p>下面这份清单,<strong>任何一家中大型企业都应该有人按月对照</strong>。打勾就放心,打叉就排进 OKR。</p><h3 id="_13-1-终端-凭证" tabindex="-1">13.1 终端 &amp; 凭证 <a class="header-anchor" href="#_13-1-终端-凭证" aria-label="Permalink to &quot;13.1 终端 &amp; 凭证&quot;">​</a></h3><ul><li>[ ] 所有终端装 EDR(不是只杀软),有集中管控台</li><li>[ ] LSASS 保护模式(RunAsPPL)开启</li><li>[ ] Windows Credential Guard 在域内全员开启</li><li>[ ] 浏览器禁用密码保存,公司 SSO + MFA</li><li>[ ] SSH 私钥按角色 / 环境拆分,有过期机制</li><li>[ ] 任何配置文件不准 hard-code 密码 / token,统一走 Vault / KMS</li><li>[ ] 用户登录无密码方案(FIDO2 / Smart Card)优先</li></ul><h3 id="_13-2-域-ad" tabindex="-1">13.2 域 &amp; AD <a class="header-anchor" href="#_13-2-域-ad" aria-label="Permalink to &quot;13.2 域 &amp; AD&quot;">​</a></h3><ul><li>[ ] <strong>Tiered Admin Model</strong> 落地——域管账户绝不登录普通终端</li><li>[ ] 域管账户从 PAW(管理专用工作站)登录</li><li>[ ] <code>krbtgt</code> 账户密码每半年重置一次</li><li>[ ] 服务账户全部使用 gMSA,<strong>不再人工管密码</strong></li><li>[ ] BloodHound 定期审计,清理 ACL 错配</li><li>[ ] LAPS(本地管理员密码自动化)部署,每台终端本地管理员密码不一样</li><li>[ ] 禁用 NTLM(至少 NTLMv1),全走 Kerberos</li></ul><h3 id="_13-3-网络分段" tabindex="-1">13.3 网络分段 <a class="header-anchor" href="#_13-3-网络分段" aria-label="Permalink to &quot;13.3 网络分段&quot;">​</a></h3><ul><li>[ ] 办公网 / 开发网 / 生产网 / 域控网 严格分段</li><li>[ ] 默认禁止跨段,只开必需端口</li><li>[ ] 生产数据库不接受任何&quot;个人电脑直连&quot;</li><li>[ ] SMB / WMI / WinRM 在内部不允许&quot;任意主机互通&quot;,只允许从 jump server</li><li>[ ] 出口流量白名单,禁止终端直连公共 DNS(8.8.8.8 / 1.1.1.1)</li></ul><h3 id="_13-4-监控-检测" tabindex="-1">13.4 监控 &amp; 检测 <a class="header-anchor" href="#_13-4-监控-检测" aria-label="Permalink to &quot;13.4 监控 &amp; 检测&quot;">​</a></h3><ul><li>[ ] Sysmon / auditd 在所有终端开启,日志集中收上来</li><li>[ ] SIEM 至少覆盖 ATT&amp;CK 的关键技术(凭证窃取 / 横向 / 持久化)</li><li>[ ] LSASS 访问监控(任何 <code>OpenProcess</code> LSASS 都审计)</li><li>[ ] DNS 异常监控(长子域名 / 高熵字符串 / 高频查询)</li><li>[ ] 流量做 JA3 指纹分析,有已知坏指纹库</li><li>[ ] 蜜罐账户 + Canary Token 部署</li><li>[ ] 应急响应预案有,每年至少一次桌面演练</li><li>[ ] 备份<strong>离线 + 不可改</strong>(防勒索病毒)</li></ul><h3 id="_13-5-软性管理" tabindex="-1">13.5 软性管理 <a class="header-anchor" href="#_13-5-软性管理" aria-label="Permalink to &quot;13.5 软性管理&quot;">​</a></h3><ul><li>[ ] 全员钓鱼演练,每季度一次</li><li>[ ] 离职流程包括&quot;立即撤销所有凭证&quot;</li><li>[ ] 第三方供应商接入有专门网段 + 时限</li><li>[ ] 关键操作有双人审批</li><li>[ ] 红蓝紫队演练每年至少一次</li></ul><hr><h2 id="十四、本篇心智总结" tabindex="-1">十四、本篇心智总结 <a class="header-anchor" href="#十四、本篇心智总结" aria-label="Permalink to &quot;十四、本篇心智总结&quot;">​</a></h2><ul><li><strong>打进来只是开始</strong>,真正的危险在内网这 30 步</li><li>内网攻击 90% 是&quot;用合法工具做不合法事&quot;,<strong>WAF 和签名拦不住,只有行为分析能发现</strong></li><li><strong>凭证是货币</strong>,LSASS / SSH key / 浏览器 cookie 是三个最大金矿</li><li><strong>横向不需要打洞,用偷来的凭证就行</strong>(Pass-the-Hash / Pass-the-Ticket / SSH 密钥)</li><li><strong>AD 域是单点信任根</strong>,DC 沦陷 = 公司沦陷;<code>krbtgt</code> 是最关键的账户</li><li><strong>C2 流量越来越像合法流量</strong>,只能靠行为基线 / 指纹 / 时序检测</li><li><strong>MITRE ATT&amp;CK 是攻防共同语言</strong>,蓝队不懂 ATT&amp;CK 没法做覆盖率管理</li><li><strong>防御核心是纵深 + 最小权限 + 快速发现</strong>——别指望边界,要假设&quot;已经有人在里面&quot;</li><li><strong>零信任(Zero Trust)的本质</strong>就是把&quot;内网默认信任&quot;这个 30 年的假设彻底废掉</li></ul><blockquote><p>这一篇所有内容<strong>只到心智层,不武器化</strong>。具体怎么演练,要去授权环境(Hack The Box / TryHackMe / 公司自建靶场)亲手做——<strong>蓝队不亲手走一遍,永远做不出能发现这些事的检测规则</strong>。下一篇 24-红蓝紫队会接着讲&quot;怎么把攻防演练工程化&quot;——红队怎么写演练计划、蓝队怎么按 ATT&amp;CK 评分覆盖率、紫队(Purple Team)怎么把&quot;红队找的洞&quot;变成&quot;蓝队的检测规则&quot;,真正闭环。</p></blockquote><hr><p>下一篇:<code>24-红蓝紫队.md</code>,讲清楚为什么&quot;只有红队不够、只有蓝队也不够&quot;——攻击者演练完没人接,等于花钱买了一份&quot;过去式漏洞清单&quot;;防御方不知道自己漏在哪,等于盲人摸象。Purple Team 是把红蓝拉到一张桌子上的工程实践,<strong>这十年安全行业最值钱的角色转变就在这里</strong>——也是为什么大厂安全团队都在招&quot;紫队工程师&quot;而不是单纯的&quot;红/蓝队&quot;。</p>`,164)])])}const h=n(e,[["render",r]]);export{u as __pageData,h as default};
